import numpy as np
import pickle
from sklearn import datasets, linear_model
from sklearn.metrics import mean_squared_error

data = np.loadtxt('email_spam',dtype=np.int)

X = data[:,:-1]
Y = data[:,-1:]


regr = linear_model.LogisticRegression()

regr.fit(X, Y.reshape(-1))

f = open("lm.pkl","wb")
pickle.dump(regr, f)
f.close()